import React, { useEffect, useState } from "react";
import { Box, Typography, Container, Grid, useMediaQuery } from "@mui/material";

const textOptions = ["React.js", "React Native", "Full Stack Development"];




export default function Intro() {
  const [currentText, setCurrentText] = useState("");
  const [textIndex, setTextIndex] = useState(0);
  const [charIndex, setCharIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  useEffect(() => {
    const currentString = textOptions[textIndex];
    const timeout = setTimeout(() => {
      if (isDeleting) {
        setCurrentText(currentString.substring(0, charIndex - 1));
        setCharIndex(charIndex - 1);
      } else {
        setCurrentText(currentString.substring(0, charIndex + 1));
        setCharIndex(charIndex + 1);
      }

      // If we reach the end of the string, start deleting
      if (!isDeleting && charIndex === currentString.length) {
        setIsDeleting(true);
      } 
      // If we are deleting and reach the start, move to the next string
      else if (isDeleting && charIndex === 0) {
        setIsDeleting(false);
        setTextIndex((textIndex + 1) % textOptions.length);
      }
    }, isDeleting ? 50 : 150); // Adjust typing speed here

    return () => clearTimeout(timeout);
  }, [currentText, charIndex, isDeleting, textIndex]);

  // Use media query to determine if the screen is small (mobile view)
  const isMobile = useMediaQuery((theme) => theme.breakpoints.down("md"));

  return (
    <Container maxWidth="xl">
    <section style={styles.hero} id="home">
      <div style={styles.socialLinks}>
        <a href="#" style={styles.socialIcon}><i className="fa-brands fa-github"></i></a>
        <a href="#" style={styles.socialIcon}><i className="fa-brands fa-discord"></i></a>
        <a href="#" style={styles.socialIcon}><i className="fa-brands fa-twitter"></i></a>
      </div>

      <div style={styles.heroContent}>
        <div style={styles.heroText}>
          <h1>
            Hi <span style={styles.accent}>web designer</span> and<br />
            <span style={styles.accent}>front-end developer</span>
          </h1>
          <p style={styles.heroDescription}>
            He crafts responsive websites where technologies<br />
            meet creativity
          </p>
          <button style={styles.buttonPrimary}>Contact me !!</button>
        </div>

        <div style={styles.heroImage}>
          <img src="assets/header_img.png" alt="Elias in a hoodie" />
          <div style={styles.statusBadge}>
            <div style={styles.statusDot}></div>
            <p>Currently working on <span style={styles.bold}>Portfolio</span></p>
          </div>
          <div style={styles.geometricElement}>
            <img src="assets/hero_sub.png" alt="Geometric design" />
          </div>
          <div style={styles.geometricElement}>
            <img src="assets/Dots.png" alt="Dot pattern" />
          </div>
        </div>
      </div>
    </section>
  </Container>
  );
}


const styles = {
  hero: {
    display: 'flex',
    alignItems: 'center',
    padding: '80px 0 40px',
    position: 'relative',
  },
  socialLinks: {
    position: 'fixed',
    left: '20px',
    top: '50%',
    transform: 'translateY(-50%)',
    display: 'flex',
    flexDirection: 'column',
    gap: '16px',
  },
  socialIcon: {
    fontSize: '20px',
    transition: 'color 0.3s',
  },
  heroContent: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    width: '100%',
  },
  heroText: {
    fontSize: '32px',
    marginBottom: '32px',
    lineHeight: 1.2,
  },
  heroDescription: {
    color: '#abb2bf',
    marginBottom: '32px',
  },
  buttonPrimary: {
    background: 'transparent',
    color: '#fff',
    border: '1px solid #c778dd',
    padding: '8px 16px',
    cursor: 'pointer',
    fontFamily: "'Fira Code', monospace",
    transition: 'background-color 0.3s',
  },
  heroImage: {
    position: 'relative',
  },
  statusBadge: {
    position: 'absolute',
    bottom: '16px',
    left: 0,
    backgroundColor: '#191919',
    border: '1px solid #c778dd',
    padding: '8px 16px',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
  },
  statusDot: {
    width: '12px',
    height: '12px',
    backgroundColor: '#c778dd',
    borderRadius: '50%',
  },
  geometricElement: {
    position: 'absolute',
    width: "160px",
    height: "100px",
    /* border: 1px solid var(--accent); */
    top:" 94px",
    left:" -175px"
  },
  accent: {
    color: '#c778dd',
  },
  bold: {
    fontWeight: 700,
  },

};
